-- 1. Corrigir enum status para incluir os valores novos
ALTER TABLE `accounts`
  MODIFY COLUMN `status` enum('connecting','connected','disconnected','active','inactive','error') NOT NULL DEFAULT 'disconnected';

-- 2. Tornar identifier nullable (o schema original tinha NOT NULL mas o banco já é nullable — alinhar com o schema)
ALTER TABLE `accounts`
  MODIFY COLUMN `identifier` varchar(320) NULL;

-- 3. Corrigir igAccessToken para text (estava varchar(512))
ALTER TABLE `accounts`
  MODIFY COLUMN `igAccessToken` text NULL;

-- 4. Corrigir smtpSecure para boolean (estava enum)
ALTER TABLE `accounts`
  MODIFY COLUMN `smtpSecure` tinyint(1) NULL DEFAULT 1;

-- 5. Corrigir imapPassword para text (estava varchar(255))
ALTER TABLE `accounts`
  MODIFY COLUMN `imapPassword` text NULL;

-- 6. Corrigir smtpPassword para text (estava varchar(255))
ALTER TABLE `accounts`
  MODIFY COLUMN `smtpPassword` text NULL;

